import { mkdtempSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { afterAll, beforeAll, describe, expect, it, vi } from "vitest";

/**
 * Lock the Claude Agent SDK option shape the handler passes to `query()`.
 *
 * `settingSources: ["user", "project"]` is the single knob that drives two
 * separate behaviors:
 *   - `"project"` — loads the workspace CLAUDE.md generated by bootstrap,
 *     which carries the agent's identity + First Tree SDK reference.
 *   - `"user"` — inherits the operator's local ~/.claude/settings.json so
 *     their thinking mode, effortLevel, plugins, skills, hooks, statusLine,
 *     and MCP servers carry over. Server-managed fields (model, systemPrompt,
 *     env, permissionMode) still win because they ride as explicit options.
 *
 * Dropping either entry silently breaks one of those two contracts with no
 * runtime error — exactly the shape of regression we hit when this array
 * was `["project"]` only (user-level "model": "opus" stopped inheriting
 * and agents silently fell back to Sonnet). This test pins both entries.
 */

const capturedCalls: Array<{ options?: Record<string, unknown> }> = [];

vi.mock("@anthropic-ai/claude-agent-sdk", () => {
  const fakeQuery = {
    [Symbol.asyncIterator]() {
      return {
        next: async () => ({ done: true, value: undefined }),
      };
    },
    close: () => {},
    setModel: async () => {},
  };
  return {
    query: (args: { options?: Record<string, unknown> }) => {
      capturedCalls.push({ options: args?.options });
      return fakeQuery;
    },
  };
});

import { createClaudeCodeHandler } from "../handlers/claude-code.js";
import { createAgentConfigCache } from "../runtime/agent-config-cache.js";
import type { SessionContext } from "../runtime/handler.js";
import { mockCtxPlumbing } from "./test-helpers.js";

const AGENT_ID = "019d9a97-90b0-716b-8317-a8c0be8430d7";

let workspaceRoot: string;

beforeAll(() => {
  workspaceRoot = mkdtempSync(join(tmpdir(), "ftt-sdk-options-"));
});

afterAll(() => {
  rmSync(workspaceRoot, { recursive: true, force: true });
});

function buildCache() {
  const stubSdk = {
    fetchAgentConfig: async () => ({
      agentId: AGENT_ID,
      version: 1,
      payload: { prompt: { append: "" }, model: "", mcpServers: [], env: [], gitRepos: [] },
      updatedAt: new Date().toISOString(),
      updatedBy: "test",
    }),
  } as unknown as Parameters<typeof createAgentConfigCache>[0]["sdk"];
  return createAgentConfigCache({ sdk: stubSdk });
}

function buildSessionCtx(chatId: string): SessionContext {
  const sendMessage = async () => undefined;
  return {
    agent: {
      agentId: AGENT_ID,
      inboxId: "inbox-test",
      displayName: "test",
      type: "agent",
      visibility: "organization",
      delegateMention: null,
      metadata: {},
    },
    sdk: { serverUrl: "http://test", sendMessage } as unknown as SessionContext["sdk"],
    chatId,
    log: () => {},
    emitEvent: () => {},
    ...mockCtxPlumbing({ sendMessage }, chatId),
  };
}

describe("claude-code handler — SDK options", () => {
  it("passes settingSources=['user','project'] to claudeQuery", async () => {
    capturedCalls.length = 0;

    const cache = buildCache();
    await cache.refresh(AGENT_ID);

    const handler = createClaudeCodeHandler({ workspaceRoot, agentConfigCache: cache });
    const ctx = buildSessionCtx("chat-settings");
    await handler.start(
      { id: "msg-1", chatId: "chat-settings", senderId: "user", format: "text", content: "hi", metadata: null },
      ctx,
    );

    expect(capturedCalls).toHaveLength(1);
    const options = capturedCalls[0]?.options;
    expect(options?.settingSources).toEqual(["user", "project"]);

    await handler.shutdown();
  });

  it("sets bypassPermissions + allowDangerouslySkipPermissions so user permission lists cannot gate the agent", async () => {
    capturedCalls.length = 0;

    const cache = buildCache();
    await cache.refresh(AGENT_ID);

    const handler = createClaudeCodeHandler({ workspaceRoot, agentConfigCache: cache });
    const ctx = buildSessionCtx("chat-perm");
    await handler.start(
      { id: "msg-2", chatId: "chat-perm", senderId: "user", format: "text", content: "hi", metadata: null },
      ctx,
    );

    const options = capturedCalls[0]?.options;
    expect(options?.permissionMode).toBe("bypassPermissions");
    expect(options?.allowDangerouslySkipPermissions).toBe(true);

    await handler.shutdown();
  });

  it("disables AskUserQuestion via the SDK disallowedTools list", async () => {
    capturedCalls.length = 0;

    const cache = buildCache();
    await cache.refresh(AGENT_ID);

    const handler = createClaudeCodeHandler({ workspaceRoot, agentConfigCache: cache });
    const ctx = buildSessionCtx("chat-disallow");
    await handler.start(
      { id: "msg-3", chatId: "chat-disallow", senderId: "user", format: "text", content: "hi", metadata: null },
      ctx,
    );

    const options = capturedCalls[0]?.options;
    // AskUserQuestion is not supported in First Tree — it is disabled at the
    // SDK level via disallowedTools rather than bridged through canUseTool.
    expect(options?.disallowedTools).toContain("AskUserQuestion");
    expect(options?.canUseTool).toBeUndefined();

    await handler.shutdown();
  });
});
